from abc import ABC, abstractmethod
from typing import List, Dict, Any, Optional
import numpy as np

class FeatureEncoder(ABC):
    @abstractmethod
    def encode(self, data: np.ndarray) -> List[Dict[str, Any]]:
        pass

    @abstractmethod
    def get_circuit_depth(self, n_features: int) -> int:
        pass

    @abstractmethod
    def validate_input(self, data: np.ndarray) -> bool:
        pass

class AngleEncoder(FeatureEncoder):
    def __init__(self, rotation_axis: str = "Y", repetitions: int = 1):
        self.rotation_axis = rotation_axis.upper()
        self.repetitions = repetitions
        if self.rotation_axis not in ["X", "Y", "Z"]:
            raise ValueError("rotation_axis must be X, Y, or Z")

    def encode(self, data: np.ndarray) -> List[Dict[str, Any]]:
        if not self.validate_input(data):
            raise ValueError("Invalid input data")

        if data.ndim == 1:
            data = data.reshape(1, -1)

        n_samples, n_features = data.shape
        instructions = []

        for sample_idx in range(n_samples):
            sample_instructions = []
            for rep in range(self.repetitions):
                for qubit_idx, angle in enumerate(data[sample_idx]):
                    sample_instructions.append({
                        "gate": f"R{self.rotation_axis}",
                        "qubit": qubit_idx,
                        "parameter": float(angle),
                        "layer": rep
                    })
            instructions.append(sample_instructions)

        return instructions

    def get_circuit_depth(self, n_features: int) -> int:
        return self.repetitions

    def validate_input(self, data: np.ndarray) -> bool:
        if not isinstance(data, np.ndarray):
            return False
        if np.any(np.isnan(data)) or np.any(np.isinf(data)):
            return False
        return True

class BasisEncoder(FeatureEncoder):
    def __init__(self, num_qubits: int):
        self.num_qubits = num_qubits
        self.max_value = 2 ** num_qubits - 1

    def encode(self, data: np.ndarray) -> List[Dict[str, Any]]:
        if not self.validate_input(data):
            raise ValueError("Invalid input data for basis encoding")

        if data.ndim == 1:
            data = data.reshape(-1, 1)

        instructions = []

        for sample_idx in range(len(data)):
            value = int(data[sample_idx, 0])
            binary = format(value, f'0{self.num_qubits}b')

            sample_instructions = []
            for qubit_idx, bit in enumerate(reversed(binary)):
                if bit == '1':
                    sample_instructions.append({
                        "gate": "X",
                        "qubit": qubit_idx,
                        "layer": 0
                    })

            instructions.append(sample_instructions)

        return instructions

    def get_circuit_depth(self, n_features: int) -> int:
        return 1

    def validate_input(self, data: np.ndarray) -> bool:
        if not isinstance(data, np.ndarray):
            return False
        if np.any(np.isnan(data)):
            return False
        if data.ndim == 1:
            values = data
        else:
            values = data[:, 0]
        if np.any(values < 0) or np.any(values > self.max_value):
            return False
        if not np.all(values == values.astype(int)):
            return False
        return True

class FeatureEncoderFactory:
    @staticmethod
    def create(encoder_type: str, config: Dict[str, Any]) -> FeatureEncoder:
        if encoder_type == "angle":
            return AngleEncoder(
                rotation_axis=config.get("rotation_axis", "Y"),
                repetitions=config.get("repetitions", 1)
            )
        elif encoder_type == "basis":
            if "num_qubits" not in config:
                raise ValueError("num_qubits required for basis encoder")
            return BasisEncoder(num_qubits=config["num_qubits"])
        else:
            raise ValueError(f"Unknown encoder type: {encoder_type}")

from dataclasses import dataclass, field
from typing import Dict, Any, List, Callable, Tuple
import numpy as np

@dataclass
class MeasurementResult:
    counts: Dict[str, int]
    num_qubits: int
    shots: int

class PostProcessingPipeline:
    def __init__(self):
        self.steps: List[Tuple[str, Callable]] = []

    def add_step(self, step_fn: Callable, name: str):
        self.steps.append((name, step_fn))
        return self

    def process(self, result: MeasurementResult) -> Dict[str, Any]:
        output = {
            "raw_counts": result.counts,
            "num_qubits": result.num_qubits,
            "shots": result.shots
        }

        probabilities = counts_to_probabilities(result.counts, result.shots)
        output["probabilities"] = probabilities

        for name, step_fn in self.steps:
            try:
                step_result = step_fn(probabilities, result.num_qubits)
                output[name] = step_result
            except Exception as e:
                output[f"{name}_error"] = str(e)

        return output

def counts_to_probabilities(counts: Dict[str, int], shots: int) -> Dict[str, float]:
    if shots <= 0:
        raise ValueError("shots must be positive")
    return {bitstring: count / shots for bitstring, count in counts.items()}

def calculate_z_expectations(probabilities: Dict[str, float], num_qubits: int) -> Dict[str, float]:
    expectations = {}

    for q in range(num_qubits):
        z_exp = 0.0
        for bitstring, prob in probabilities.items():
            bit_idx = num_qubits - 1 - q
            if bit_idx < len(bitstring):
                bit = int(bitstring[bit_idx])
                eigenvalue = 1 if bit == 0 else -1
                z_exp += prob * eigenvalue
        expectations[f"Z_{q}"] = z_exp

    return expectations

def calculate_entropy(probabilities: Dict[str, float], num_qubits: int = None) -> float:
    probs = np.array(list(probabilities.values()))
    probs = probs[probs > 0]
    entropy = -np.sum(probs * np.log2(probs))
    return float(entropy)

def calculate_parity(probabilities: Dict[str, float], num_qubits: int = None) -> float:
    parity = 0.0
    for bitstring, prob in probabilities.items():
        eigenvalue = 1 if bitstring.count('1') % 2 == 0 else -1
        parity += prob * eigenvalue
    return parity

# Example usage:
pipeline = PostProcessingPipeline()
pipeline.add_step(calculate_z_expectations, "z_expectations")
pipeline.add_step(calculate_entropy, "entropy")
pipeline.add_step(calculate_parity, "parity")

result = MeasurementResult(
    counts={"00": 450, "11": 550},
    num_qubits=2,
    shots=1000
)

processed = pipeline.process(result)

from dataclasses import dataclass, field
from typing import List, Dict, Any, Callable, Optional
import time
import numpy as np
import uuid

@dataclass
class BatchJob:
    batch_id: str
    circuits: List[Any]
    shots: int
    priority: int = 0
    created_at: float = field(default_factory=time.time)

@dataclass
class BatchResult:
    batch_id: str
    results: List[Dict]
    execution_time: float
    success_count: int
    failure_count: int

class PerformanceTracker:
    def __init__(self, history_size: int = 50):
        self.history_size = history_size
        self.history: List[Dict] = []

    def record(self, batch_size: int, execution_time: float,
               success_count: int, failure_count: int):
        total = success_count + failure_count
        failure_rate = failure_count / total if total > 0 else 0
        throughput = success_count / execution_time if execution_time > 0 else 0

        self.history.append({
            "batch_size": batch_size,
            "execution_time": execution_time,
            "success_count": success_count,
            "failure_count": failure_count,
            "failure_rate": failure_rate,
            "throughput": throughput,
            "adjusted_throughput": throughput * (1 - failure_rate),
            "timestamp": time.time()
        })

        if len(self.history) > self.history_size:
            self.history = self.history[-self.history_size:]

    def get_optimal_batch_size(self, min_size: int = 10, max_size: int = 200) -> int:
        if len(self.history) < 3:
            return (min_size + max_size) // 2

        size_performance: Dict[int, List[float]] = {}

        for entry in self.history[-20:]:
            size = entry["batch_size"]
            adj_throughput = entry["adjusted_throughput"]

            if size not in size_performance:
                size_performance[size] = []
            size_performance[size].append(adj_throughput)

        best_size = min_size
        best_throughput = 0

        for size, throughputs in size_performance.items():
            avg_throughput = np.mean(throughputs)
            if avg_throughput > best_throughput:
                best_throughput = avg_throughput
                best_size = size

        return max(min_size, min(best_size, max_size))

class AdaptiveBatchProcessor:
    def __init__(self, initial_batch_size: int = 50, max_retries: int = 3):
        self.batch_size = initial_batch_size
        self.max_retries = max_retries
        self.tracker = PerformanceTracker()

    def create_batches(self, circuits: List[Any], shots: int) -> List[BatchJob]:
        batches = []

        for i in range(0, len(circuits), self.batch_size):
            batch_circuits = circuits[i:i + self.batch_size]
            batch = BatchJob(
                batch_id=f"batch_{uuid.uuid4().hex[:8]}",
                circuits=batch_circuits,
                shots=shots
            )
            batches.append(batch)

        return batches

    def execute_batch(self, batch: BatchJob,
                      executor: Callable[[Any, int], Dict]) -> BatchResult:
        start_time = time.time()
        results = []
        success_count = 0
        failure_count = 0

        for circuit in batch.circuits:
            result = None

            for attempt in range(self.max_retries):
                try:
                    result = executor(circuit, batch.shots)
                    success_count += 1
                    break
                except Exception as e:
                    if attempt == self.max_retries - 1:
                        result = {"error": str(e)}
                        failure_count += 1

            results.append(result)

        execution_time = time.time() - start_time

        self.tracker.record(
            batch_size=len(batch.circuits),
            execution_time=execution_time,
            success_count=success_count,
            failure_count=failure_count
        )

        return BatchResult(
            batch_id=batch.batch_id,
            results=results,
            execution_time=execution_time,
            success_count=success_count,
            failure_count=failure_count
        )

    def process_all(self, circuits: List[Any], shots: int,
                    executor: Callable[[Any, int], Dict]) -> List[BatchResult]:
        self.batch_size = self.tracker.get_optimal_batch_size()
        batches = self.create_batches(circuits, shots)

        all_results = []

        for i, batch in enumerate(batches):
            result = self.execute_batch(batch, executor)
            all_results.append(result)

            if (i + 1) % 5 == 0:
                self.batch_size = self.tracker.get_optimal_batch_size()

        return all_results

from dataclasses import dataclass, field
from typing import List, Dict, Any, Optional, Callable
import numpy as np

@dataclass
class DataSchema:
    name: str
    expected_shape: tuple
    min_value: Optional[float] = None
    max_value: Optional[float] = None
    allow_nan: bool = False
    allow_inf: bool = False

@dataclass
class ValidationResult:
    is_valid: bool
    errors: List[str]
    warnings: List[str]
    data_summary: Dict[str, Any]

class DataValidator:
    def __init__(self, schema: DataSchema):
        self.schema = schema
        self.custom_rules: List[Callable] = []

    def add_rule(self, rule_fn: Callable[[np.ndarray], Optional[str]]):
        self.custom_rules.append(rule_fn)
        return self

    def validate(self, data: np.ndarray) -> ValidationResult:
        errors = []
        warnings = []

        errors.extend(self._check_shape(data))
        errors.extend(self._check_special_values(data))
        errors.extend(self._check_bounds(data))

        for rule_fn in self.custom_rules:
            result = rule_fn(data)
            if result:
                errors.append(result)

        data_summary = self._generate_summary(data)

        if data_summary.get("sparsity", 0) > 0.5:
            warnings.append("Data is more than 50% zeros")

        return ValidationResult(
            is_valid=len(errors) == 0,
            errors=errors,
            warnings=warnings,
            data_summary=data_summary
        )

    def _check_shape(self, data: np.ndarray) -> List[str]:
        errors = []

        if data.ndim == 1:
            actual_shape = (data.shape[0],)
        else:
            actual_shape = data.shape[1:]

        if actual_shape != self.schema.expected_shape:
            if len(actual_shape) != len(self.schema.expected_shape):
                errors.append(
                    f"{self.schema.name}: Dimension mismatch - "
                    f"expected {len(self.schema.expected_shape)}D, got {len(actual_shape)}D"
                )
            else:
                errors.append(
                    f"{self.schema.name}: Shape mismatch - "
                    f"expected {self.schema.expected_shape}, got {actual_shape}"
                )

        return errors

    def _check_bounds(self, data: np.ndarray) -> List[str]:
        errors = []

        if self.schema.min_value is not None:
            min_val = np.nanmin(data)
            if min_val < self.schema.min_value:
                errors.append(
                    f"{self.schema.name}: Values below minimum "
                    f"({min_val:.4f} < {self.schema.min_value})"
                )

        if self.schema.max_value is not None:
            max_val = np.nanmax(data)
            if max_val > self.schema.max_value:
                errors.append(
                    f"{self.schema.name}: Values above maximum "
                    f"({max_val:.4f} > {self.schema.max_value})"
                )

        return errors

    def _check_special_values(self, data: np.ndarray) -> List[str]:
        errors = []

        nan_count = np.sum(np.isnan(data))
        if nan_count > 0 and not self.schema.allow_nan:
            errors.append(
                f"{self.schema.name}: Contains {nan_count} NaN values"
            )

        inf_count = np.sum(np.isinf(data))
        if inf_count > 0 and not self.schema.allow_inf:
            errors.append(
                f"{self.schema.name}: Contains {inf_count} Inf values"
            )

        return errors

    def _generate_summary(self, data: np.ndarray) -> Dict[str, Any]:
        return {
            "shape": data.shape,
            "dtype": str(data.dtype),
            "min": float(np.nanmin(data)),
            "max": float(np.nanmax(data)),
            "mean": float(np.nanmean(data)),
            "std": float(np.nanstd(data)),
            "nan_count": int(np.sum(np.isnan(data))),
            "inf_count": int(np.sum(np.isinf(data))),
            "sparsity": float(np.sum(data == 0) / data.size)
        }
